import requests

BASE_URL = "http://localhost:8080"
LOGIN_URL = f"{BASE_URL}/api/v1/auth/login"
CLAIMS_URL = f"{BASE_URL}/api/v1/claims"
TIMEOUT = 30

def test_post_api_v1_claims_missing_visit_id_returns_400():
    login_payload = {
        "identifier": "superadmin@tba.sa",
        "password": "Admin@123"
    }
    try:
        # Login and get token
        login_resp = requests.post(LOGIN_URL, json=login_payload, timeout=TIMEOUT)
        assert login_resp.status_code == 200, f"Login failed with status code {login_resp.status_code}"
        login_data = login_resp.json()
        token = login_data.get("data", {}).get("token")
        assert token, "JWT token not found in login response"

        headers = {
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json"
        }

        # Prepare claim payload missing visitId, either empty object or with lines missing visitId
        claim_payload_options = [
            {},
            {
                "lines": [
                    {
                        # Intentionally no visitId, minimal fields
                        "serviceId": 1234
                    }
                ]
            }
        ]

        # Test both payload options
        for claim_payload in claim_payload_options:
            resp = requests.post(CLAIMS_URL, json=claim_payload, headers=headers, timeout=TIMEOUT)
            # Accept either 400 or 500 for business rule exception on missing visitId
            assert resp.status_code in (400, 500), (
                f"Expected status 400 or 500 for missing visitId, got {resp.status_code} with response: {resp.text}"
            )

    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

test_post_api_v1_claims_missing_visit_id_returns_400()

import requests

BASE_URL = "http://localhost:8080"
LOGIN_ENDPOINT = "/api/v1/auth/login"
ELIGIBILITY_ENDPOINT = "/api/v1/members/eligibility"
TIMEOUT = 30

def test_get_api_v1_members_eligibility_with_valid_query():
    login_payload = {
        "identifier": "superadmin@tba.sa",
        "password": "Admin@123"
    }
    headers = {
        "Content-Type": "application/json"
    }
    # Login and get the JWT token
    try:
        login_resp = requests.post(
            BASE_URL + LOGIN_ENDPOINT,
            json=login_payload,
            headers=headers,
            timeout=TIMEOUT
        )
        assert login_resp.status_code == 200, f"Login failed with status {login_resp.status_code}"
        json_login = login_resp.json()
        token = json_login.get("data", {}).get("token")
        assert token, "JWT token not found in login response"
    except requests.RequestException as e:
        assert False, f"Login request failed: {e}"

    # Use the token to call the eligibility endpoint
    headers_auth = {
        "Authorization": f"Bearer {token}"
    }
    params = {
        "query": "1234567890"
    }
    try:
        eligibility_resp = requests.get(
            BASE_URL + ELIGIBILITY_ENDPOINT,
            headers=headers_auth,
            params=params,
            timeout=TIMEOUT
        )
        # Expect 200 or 404 but NOT 500
        assert eligibility_resp.status_code in (200, 404), f"Unexpected status code: {eligibility_resp.status_code}"
        assert eligibility_resp.status_code != 500, "Server error 500 encountered"
    except requests.RequestException as e:
        assert False, f"Eligibility request failed: {e}"

test_get_api_v1_members_eligibility_with_valid_query()

